### Extend Playwright Test with Custom Fixtures (TypeScript)

Source: https://github.com/microsoft/playwright/blob/main/docs/src/test-fixtures-js.md

This TypeScript code extends the base Playwright `test` object to include custom fixtures `todoPage` and `settingsPage`. It defines their types, sets up the fixtures (e.g., initializing `TodoPage` and adding items), yields control to the test, and cleans up after the test, demonstrating how to create reusable test setup and teardown logic.

```typescript
import { test as base } from '@playwright/test';
import { TodoPage } from './todo-page';
import { SettingsPage } from './settings-page';

// Declare the types of your fixtures.
type MyFixtures = {
  todoPage: TodoPage;
  settingsPage: SettingsPage;
};

// Extend base test by providing "todoPage" and "settingsPage".
// This new "test" can be used in multiple test files, and each of them will get the fixtures.
export const test = base.extend<MyFixtures>({
  todoPage: async ({ page }, use) => {
    // Set up the fixture.
    const todoPage = new TodoPage(page);
    await todoPage.goto();
    await todoPage.addToDo('item1');
    await todoPage.addToDo('item2');

    // Use the fixture value in the test.
    await use(todoPage);

    // Clean up the fixture.
    await todoPage.removeAll();
  },

  settingsPage: async ({ page }, use) => {
    await use(new SettingsPage(page));
  },
});
export { expect } from '@playwright/test';
```
